import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო, რომ უკეთ გაიცნო შენი ფსიქოტიპი?"
};

export default function PersonalAIMentor({ userType, userId }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [style, setStyle] = useState({}); // personalization, შემდგომ შეგიძლია გამოიყენო

  const mbti = userType || "DEFAULT";

  // ✅ ჩატის აღდგენა სერვერიდან
  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const res = await fetch(`http://localhost:5000/api/chat-reply/history/${userId}`);
        const data = await res.json();

        if (data.history && data.history.length > 0) {
          setMessages(data.history);
        } else {
          const first = firstMessages[mbti] || firstMessages.DEFAULT;
          setMessages([{ role: "ai", text: first }]);
        }
      } catch (err) {
        console.error(err);
        const first = firstMessages[mbti] || firstMessages.DEFAULT;
        setMessages([{ role: "ai", text: first }]);
      }
    };

    fetchHistory();
  }, [mbti, userId]);

  // ✅ მესიჯის გაგზავნა
  const sendMessage = async () => {
    if (!input.trim()) return;

    const newUserMsg = { role: "user", text: input };
    setMessages(prev => [...prev, newUserMsg]);

    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: input,
          type: mbti,
          userId,
          style,
          newChat: false
        })
      });
      const data = await res.json();
      setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [
        ...prev,
        { role: "ai", text: "უკაცრავად, ახლა ჩატი ხელმისაწვდომი არ არის 😅" }
      ]);
    }

    setInput("");
  };

  // ✅ ახალი ჩატის დაწყება
  const newChat = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: "ახალი ჩატი დაიწყო 😊",
          type: mbti,
          userId,
          style,
          newChat: true
        })
      });
      const data = await res.json();
      setMessages([{ role: "ai", text: data.reply }]);
    } catch (err) {
      console.error(err);
      setMessages([{ role: "ai", text: "უკაცრავად, ახალი ჩატი ვერ დაიწყო 😅" }]);
    }
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">
        Personal AI Mentor
        <button className="new-chat-btn" onClick={newChat}>
          New Chat
        </button>
      </div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder="მომწერე..."
          rows="1"
          className="ai-textarea"
        />
        <button onClick={sendMessage}>გაგზავნა</button>
      </div>
    </div>
  );
}
